package main

import (
	"html/template"
	"net/http"
)

type Comment struct {
	Author string
	Text   string
}

var comments = []Comment{
	{"Alice", "This is a great post!"},
	{"Bob", "I love the content! <strong>Keep it up!</strong>"},
	{"Charlie", "<em>Very insightful!</em>"},
}

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	tmpl := `
	<!DOCTYPE html>
	<html lang="en">
	<head>
		<meta charset="UTF-8">
		<meta name="viewport" content="width=device-width, initial-scale=1.0">
		<title>User Comments</title>
	</head>
	<body>
		<h1>User Comments</h1>
		<ul>
			{{range .}}
				<li><strong>{{.Author}}:</strong> {{.Text | safeHTML}}</li>
			{{end}}
		</ul>
	</body>
	</html>
	`

	funcMap := template.FuncMap{
		"safeHTML": func(html string) template.HTML {
			return template.HTML(html)
		},
	}

	t, err := template.New("comments").Funcs(funcMap).Parse(tmpl)
	if err != nil {
		http.Error(w, "Failed to load template", http.StatusInternalServerError)
		return
	}

	if err := t.Execute(w, comments); err != nil {
		http.Error(w, "Failed to execute template", http.StatusInternalServerError)
	}
}

func main() {
	http.HandleFunc("/comments", commentsHandler)
	http.ListenAndServe(":8080", nil)
}